3	/**
4	 * Entry point for plugins to obtain a {@link PluginLogger}.
5	 *
6	 * <pre>
7	 *   public class MyPlugin implements SwissKitJPlugin {
8	 *       private static final PluginLogger log =
9	 *           LoggerFactory.getLogger(MyPlugin.class);
10	 *       ...
11	 *   }
12	 * </pre>
13	 *
14	 * <p>The host application installs a real {@link LoggerBinder} during startup
15	 * (typically backed by SLF4J + Logback). Until the host binds one, all loggers
16	 * are silent no-ops — safe for unit tests and isolated plugin loading.</p>
17	 */
18	public final class LoggerFactory {
19	
20	    private static volatile LoggerBinder binder = NoOpLoggerBinder.INSTANCE;
21	
22	    private LoggerFactory() {
23	    }
24	
25	    /** Returns a logger named after the given class. */
26	    public static PluginLogger getLogger(Class<?> clazz) {
27	        return binder.getLogger(clazz.getName());
28	    }
29	
30	    /** Returns a logger with the given name (typically a dotted category). */
31	    public static PluginLogger getLogger(String name) {
32	        return binder.getLogger(name);
33	    }
34	
35	    /** Package-private — used by {@link LoggerBinder#bind(LoggerBinder)}. */
36	    static void setBinder(LoggerBinder newBinder) {
37	        binder = (newBinder == null) ? NoOpLoggerBinder.INSTANCE : newBinder;
38	    }
39	}
