9	import javafx.scene.shape.*;
10	import javafx.util.Duration;
11	
12	import java.util.ArrayList;
13	import java.util.List;
14	import java.util.function.BooleanSupplier;
15	
16	/**
17	 * Generic multi-step wizard container.
18	 *
19	 * Usage:
20	 *   wizard.addStep("Select file", node, () -> validate());
21	 *   wizard.addStep("Split mode",  node, () -> true);
22	 *   wizard.addStep("Run split",   node, () -> true);
23	 *   wizard.build();
24	 */
25	public class StepWizard extends BorderPane {
26	
27	    public interface StepChangeListener {
28	        void onStepChanged(int from, int to, int total);
29	    }
30	
31	    private record Step(String title, Node content, BooleanSupplier canProceed) {}
32	
33	    // ── State ─────────────────────────────────────────────
34	    private final List<Step>   steps       = new ArrayList<>();
35	    private int                current     = 0;
36	    private StepChangeListener stepListener;
37	
38	    // ── Fixed child nodes ─────────────────────────────────
39	    private HBox   stepIndicator;
40	    private StackPane contentPane;
41	    private Button prevBtn;
42	    private Button nextBtn;
43	    private Label  stepHint;
44	
45	    // ── Colour constants ──────────────────────────────────
46	    private static final String ACCENT     = "#5b8cf7";
47	    private static final String DONE_COLOR = "#4cd97b";
48	    private static final String IDLE_COLOR = "rgba(255,255,255,0.15)";
49	
50	    public StepWizard() {
51	        setStyle("-fx-background-color: transparent;");
52	    }
53	
54	    public void addStep(String title, Node content, BooleanSupplier canProceed) {
55	        steps.add(new Step(title, content, canProceed));
56	    }
57	
58	    public void setOnStepChanged(StepChangeListener l) { this.stepListener = l; }
59	
60	    /** Called once after all steps are added to build UI */
61	    public void build() {
62	        stepIndicator = buildStepIndicator();
63	        contentPane   = new StackPane();
64	        contentPane.setStyle("-fx-background-color: transparent;");
65	
66	        // Preload all content, opacity 0, only show current step
67	        for (Step s : steps) {
68	            s.content().setOpacity(0);
69	            s.content().setVisible(false);
70	            contentPane.getChildren().add(s.content());
71	        }
72	
73	        HBox footer = buildFooter();
74	
75	        VBox top = new VBox(stepIndicator);
76	        top.setPadding(new Insets(0, 0, 20, 0));
77	
78	        setTop(top);
79	        setCenter(contentPane);
80	        setBottom(footer);
81	        BorderPane.setMargin(footer, new Insets(16, 0, 0, 0));
82	
83	        // Show the first step
84	        showStep(0, -1);
85	    }
86	
87	    // ── Step indicator ────────────────────────────────────────
88	
89	    private HBox buildStepIndicator() {
90	        HBox row = new HBox();
91	        row.setAlignment(Pos.CENTER);
92	        row.setPadding(new Insets(0, 0, 4, 0));
93	
94	        for (int i = 0; i < steps.size(); i++) {
95	            // Circular step dot
96	            StackPane dot = makeDot(i);
97	            dot.setUserData(i); // Store index for refresh use
98	            row.getChildren().add(dot);
99	
100	            // Connector line (not added after last)
101	            if (i < steps.size() - 1) {
102	                Region line = new Region();
103	                line.setPrefHeight(2);
104	                line.setMaxHeight(2);
105	                line.setMinWidth(40);
106	                HBox.setHgrow(line, Priority.ALWAYS);
107	                line.setStyle("-fx-background-color: " + IDLE_COLOR + "; -fx-background-radius: 1;");
108	                line.setUserData("line_" + i);
109	                row.getChildren().add(line);
110	            }
111	        }
112	        return row;
113	    }
114	
115	    private StackPane makeDot(int idx) {
116	        Circle circle = new Circle(12);
117	        circle.setStrokeWidth(1.5);
118	
119	        Label num = new Label(String.valueOf(idx + 1));
120	        num.setStyle("-fx-font-size: 11px; -fx-font-weight: bold;");
121	
122	        StackPane dot = new StackPane(circle, num);
123	        dot.setPrefSize(24, 24);
124	        return dot;
125	    }
126	
127	    /** Refresh all step dots and connector line styles */
128	    private void refreshIndicator() {
129	        int childIdx = 0;
130	        for (int i = 0; i < steps.size(); i++) {
131	            if (childIdx >= stepIndicator.getChildren().size()) break;
132	            StackPane dot    = (StackPane) stepIndicator.getChildren().get(childIdx);
133	            Circle    circle = (Circle)    dot.getChildren().get(0);
134	            Label     num    = (Label)     dot.getChildren().get(1);
135	            childIdx++;
136	
137	            if (i < current) {
138	                circle.setFill(Color.web(DONE_COLOR, 0.9));
139	                circle.setStroke(Color.web(DONE_COLOR));
140	                num.setText("✓");
141	                num.setStyle("-fx-font-size: 11px; -fx-font-weight: bold; -fx-text-fill: #0d0e11;");
142	            } else if (i == current) {
143	                circle.setFill(Color.web(ACCENT, 0.9));
144	                circle.setStroke(Color.web(ACCENT));
145	                num.setText(String.valueOf(i + 1));
146	                num.setStyle("-fx-font-size: 11px; -fx-font-weight: bold; -fx-text-fill: white;");
147	                ScaleTransition pulse = new ScaleTransition(Duration.millis(600), dot);
148	                pulse.setFromX(1.0); pulse.setFromY(1.0);
149	                pulse.setToX(1.12); pulse.setToY(1.12);
150	                pulse.setAutoReverse(true); pulse.setCycleCount(2);
151	                pulse.play();
152	            } else {
153	                circle.setFill(Color.web("rgba(255,255,255,0.06)"));
154	                circle.setStroke(Color.web(IDLE_COLOR));
155	                num.setText(String.valueOf(i + 1));
156	                num.setStyle("-fx-font-size: 11px; -fx-font-weight: bold; -fx-text-fill: rgba(255,255,255,0.35);");
157	            }
158	
159	            if (i < steps.size() - 1 && childIdx < stepIndicator.getChildren().size()) {
160	                Region line = (Region) stepIndicator.getChildren().get(childIdx);
161	                line.setStyle("-fx-background-color: "
162	                    + (i < current ? DONE_COLOR : IDLE_COLOR)
163	                    + "; -fx-background-radius: 1;");
164	                childIdx++;
165	            }
166	        }
167	    }
168	
169	    // ── Footer buttons ──────────────────────────────────────────
170	
171	    private HBox buildFooter() {
172	        prevBtn  = footerBtn("← ← Back", false);
173	        nextBtn  = footerBtn("Next →", true);
174	        stepHint = new Label();
175	        stepHint.setStyle("-fx-text-fill: rgba(255,255,255,0.28); -fx-font-size: 11px;");
176	
177	        prevBtn.setOnAction(e -> goTo(current - 1));
178	        nextBtn.setOnAction(e -> {
179	            Step s = steps.get(current);
180	            if (!s.canProceed().getAsBoolean()) {
181	                shakeButton(nextBtn);
182	                return;
183	            }
184	            if (current < steps.size() - 1) goTo(current + 1);
185	        });
186	
187	        Region spacer = new Region();
188	        HBox.setHgrow(spacer, Priority.ALWAYS);
189	
190	        HBox footer = new HBox(12, prevBtn, spacer, stepHint, nextBtn);
191	        footer.setAlignment(Pos.CENTER_LEFT);
192	        return footer;
193	    }
194	
195	    private Button footerBtn(String text, boolean primary) {
196	        Button btn = new Button(text);
197	        if (primary) {
198	            btn.setStyle(
199	                "-fx-background-color: #5b8cf7; -fx-text-fill: white;" +
200	                "-fx-font-size: 13px; -fx-font-weight: 500;" +
201	                "-fx-background-radius: 8; -fx-border-width: 0;" +
202	                "-fx-padding: 9 20 9 20; -fx-cursor: hand;"
203	            );
204	            btn.setOnMouseEntered(e -> btn.setStyle(btn.getStyle()
205	                .replace("#5b8cf7", "#4a7bf5")));
206	            btn.setOnMouseExited(e -> btn.setStyle(btn.getStyle()
207	                .replace("#4a7bf5", "#5b8cf7")));
208	        } else {
209	            btn.setStyle(
210	                "-fx-background-color: rgba(255,255,255,0.07);" +
211	                "-fx-border-color: rgba(255,255,255,0.12); -fx-border-width: 1;" +
212	                "-fx-text-fill: rgba(255,255,255,0.7); -fx-font-size: 13px;" +
213	                "-fx-background-radius: 8; -fx-border-radius: 8;" +
214	                "-fx-padding: 9 20 9 20; -fx-cursor: hand;"
215	            );
216	        }
217	        return btn;
218	    }
219	
220	    // ── Step transition ──────────────────────────────────────────
221	
222	    public void goTo(int idx) {
223	        if (idx < 0 || idx >= steps.size()) return;
224	        int from = current;
225	        current = idx;
226	        showStep(idx, from);
227	        if (stepListener != null) stepListener.onStepChanged(from, idx, steps.size());
228	    }
229	
230	    private void showStep(int idx, int from) {
231	        refreshIndicator();
232	        updateFooterState();
233	
234	        Node incoming = steps.get(idx).content();
235	        incoming.setVisible(true);
236	
237	        if (from < 0) {
238	            // Initial display, no animation needed
239	            incoming.setOpacity(1);
240	            return;
241	        }
242	
243	        // Determine slide direction
244	        double dir = idx > from ? 1 : -1;
245	
246	        // Hide old step
247	        Node outgoing = steps.get(from).content();
248	        TranslateTransition outTt = new TranslateTransition(Duration.millis(220), outgoing);
249	        outTt.setToX(-dir * 40);
250	        FadeTransition outFt = new FadeTransition(Duration.millis(220), outgoing);
251	        outFt.setToValue(0);
252	        ParallelTransition out = new ParallelTransition(outTt, outFt);
253	        out.setOnFinished(e -> {
254	            outgoing.setVisible(false);
255	            outgoing.setTranslateX(0);
256	        });
257	        out.play();
258	
259	        // Show new step
260	        incoming.setTranslateX(dir * 40);
261	        incoming.setOpacity(0);
262	        TranslateTransition inTt = new TranslateTransition(Duration.millis(260), incoming);
263	        inTt.setToX(0);
264	        inTt.setInterpolator(Interpolator.SPLINE(0.4, 0.0, 0.2, 1.0));
265	        FadeTransition inFt = new FadeTransition(Duration.millis(260), incoming);
266	        inFt.setToValue(1);
267	        new ParallelTransition(inTt, inFt).play();
268	    }
269	
270	    private void updateFooterState() {
271	        prevBtn.setDisable(current == 0);
272	        prevBtn.setOpacity(current == 0 ? 0.4 : 1.0);
273	
274	        boolean isLast = current == steps.size() - 1;
275	        nextBtn.setText(isLast ? "✓ Complete" : "Next →");
276	        stepHint.setText("Step " + (current + 1) + "  of " + steps.size() + "  steps");
277	    }
278	
279	    /** Shake feedback when button validation fails */
280	    private void shakeButton(Node node) {
281	        TranslateTransition shake = new TranslateTransition(Duration.millis(60), node);
282	        shake.setFromX(0); shake.setByX(8);
283	        shake.setAutoReverse(true); shake.setCycleCount(4);
284	        shake.play();
285	    }
286	
287	    // ── Public queries ──────────────────────────────────────────
288	
289	    public int  getCurrentStep()  { return current; }
290	    public int  getTotalSteps()   { return steps.size(); }
291	    public boolean isLastStep()   { return current == steps.size() - 1; }
292	}
